// Day Counter — calculate current week number and date range
const config = { start_date: '2026-03-02' };
const start = new Date(config.start_date + 'T00:00:00+01:00');
const now = new Date();
const diffDays = Math.floor((now - start) / 86400000);
const weekNum = Math.ceil((diffDays + 1) / 7);

// Get Mon-Fri of current week
const monday = new Date(now);
monday.setDate(now.getDate() - ((now.getDay() + 6) % 7));
const friday = new Date(monday);
friday.setDate(monday.getDate() + 4);

return [{ json: { weekNum, mondayDate: monday.toISOString().split('T')[0], fridayDate: friday.toISOString().split('T')[0] } }];
